function score(e,n,o){const t=document.querySelector("[name=csrfmiddlewaretoken]").value;$.post({url:"/score",contentType:"application/json",headers:{"X-CSRFToken":t},data:JSON.stringify({answer:n,points:o}),success:n=>{"ok"===n&&(console.log(e),$(e).siblings("button.points").removeClass("active"),$(e).addClass("active"))}})}$(document).ready(function(){$("a.button[disabled]").click(function(e){e.preventDefault()})});